import{_ as i,o,c as a,ag as r}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"Android Runtime - How Dalvik and ART Work","description":"Imported note from ProAndroidDev","frontmatter":{"title":"Android Runtime - How Dalvik and ART Work","description":"Imported note from ProAndroidDev"},"headers":[],"relativePath":"software-engineering/android-app-development/android-runtime-how-dalvik-and-art-work.md","filePath":"software-engineering/android-app-development/android-runtime-how-dalvik-and-art-work.md"}'),d={name:"software-engineering/android-app-development/android-runtime-how-dalvik-and-art-work.md"};function n(l,e,t,c,s,u){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="android-runtime-how-dalvik-and-art-work" tabindex="-1">Android Runtime - How Dalvik and ART Work <a class="header-anchor" href="#android-runtime-how-dalvik-and-art-work" aria-label="Permalink to &quot;Android Runtime - How Dalvik and ART Work&quot;">​</a></h1><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li>Type: webpage</li><li>Origin: <a href="https://proandroiddev.com/android-runtime-how-dalvik-and-art-work-6e57cf1c50e5" target="_blank" rel="noreferrer">https://proandroiddev.com/android-runtime-how-dalvik-and-art-work-6e57cf1c50e5</a></li><li>Author: Paulina Sadowska</li><li>Imported: 2026-04-20</li></ul><h2 id="content" tabindex="-1">Content <a class="header-anchor" href="#content" aria-label="Permalink to &quot;Content&quot;">​</a></h2><p>This article explains how Android Runtime translates app bytecode (<code>.dex</code>) into CPU-executable machine code, and how compilation strategies evolved from Dalvik to ART to balance performance, RAM usage, and install/update cost.</p><h3 id="runtime-basics" tabindex="-1">Runtime basics <a class="header-anchor" href="#runtime-basics" aria-label="Permalink to &quot;Runtime basics&quot;">​</a></h3><ul><li>APKs include <code>.dex</code> bytecode for app/library logic.</li><li>Android Runtime compiles this bytecode to machine code at runtime or ahead of runtime depending on strategy.</li><li>Runtime behavior also includes memory management and garbage collection (not the focus of this article).</li></ul><h3 id="dalvik-era-up-to-android-k" tabindex="-1">Dalvik era (up to Android K) <a class="header-anchor" href="#dalvik-era-up-to-android-k" aria-label="Permalink to &quot;Dalvik era (up to Android K)&quot;">​</a></h3><ul><li>Dalvik emphasized low RAM usage on early devices.</li><li>It relied on JIT (Just-In-Time) compilation: compiling code during execution.</li><li>Benefit: lower memory pressure from not precompiling everything.</li><li>Trade-off: slower runtime performance due to on-the-fly compilation.</li></ul><h3 id="art-in-android-l" tabindex="-1">ART in Android L <a class="header-anchor" href="#art-in-android-l" aria-label="Permalink to &quot;ART in Android L&quot;">​</a></h3><ul><li>ART introduced AOT (Ahead-Of-Time) compilation.</li><li>Code is compiled before execution, improving app runtime speed significantly.</li><li>Trade-offs: <ul><li>higher storage/RAM cost,</li><li>slower app installation and system updates due to broad precompilation.</li></ul></li></ul><h3 id="android-n-profile-guided-hybrid-model" tabindex="-1">Android N: profile-guided hybrid model <a class="header-anchor" href="#android-n-profile-guided-hybrid-model" aria-label="Permalink to &quot;Android N: profile-guided hybrid model&quot;">​</a></h3><ul><li>Android Runtime reintroduced JIT plus profile-guided compilation.</li><li>Frequently executed (&quot;hot&quot;) methods are identified and precompiled/cached.</li><li>This hybrid approach improves hot-path performance while avoiding full precompile overhead.</li><li>Precompilation is scheduled during idle/charging windows to reduce user impact.</li></ul><h3 id="android-p-cloud-common-profiles" tabindex="-1">Android P: cloud/common profiles <a class="header-anchor" href="#android-p-cloud-common-profiles" aria-label="Permalink to &quot;Android P: cloud/common profiles&quot;">​</a></h3><ul><li>Google introduced cloud-distributed common profiles for new installs.</li><li>A &quot;common core profile&quot; precompiles methods/classes commonly used by most users.</li><li>Device-specific profiling still continues after install for user-specific optimization.</li></ul><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>Dalvik prioritized RAM efficiency with JIT; ART initially prioritized execution speed with AOT.</li><li>Modern Android Runtime uses a hybrid JIT + profile-guided model for better real-world efficiency.</li><li>Cloud/common profiles improve first-run experience by pre-optimizing frequently used code paths.</li><li>Runtime compilation strategy is a major factor in startup speed, install cost, and overall UX.</li></ul>',17)])])}const h=i(d,[["render",n]]);export{p as __pageData,h as default};
